// Zaehlt die Korrektur-Versuche. $runIndex zaehlt ab 0 pro Node-Lauf.
const iter = $runIndex + 1;
const item = $input.first().json;

return [{
  json: {
    ...item,
    iteration: iter,
    maxReached: iter >= 2,
  },
}];

// Parst die Antwort von Agent 3: FREIGABE JA/NEIN + Feedback
const antwort = $input.first().json.output || '';
const approved = /FREIGABE:\s*JA/i.test(antwort);
const feedback = antwort.replace(/FREIGABE:\s*(JA|NEIN)/i, '').trim();

return [{
  json: {
    topic: $('Thema setzen').first().json.topic,
    trends: $('Trends sichern').first().json.trends,
    postDraft: $('Entwurf sichern').first().json.postDraft,
    brandCheck: antwort,
    approved,
    feedback: approved ? '' : feedback,
  },
}];

