// Rendert den freigegebenen LinkedIn-Post als schön formatierte HTML-Vorschau.
const item = $input.first().json;

const esc = (s) => String(s ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const rawPost = String(item.postDraft ?? '').trim();
const rawTrends = String(item.trends ?? '');

const topic = esc(item.topic);
const post = esc(rawPost);
const brandCheck = esc(String(item.brandCheck ?? '').trim());
const zeichen = rawPost.length;

const urls = [...new Set(rawTrends.match(/https?:\/\/[^\s)<>"']+/g) || [])].slice(0, 12);
const quellen = urls.length
  ? urls.map((u) => `<li><a href="${esc(u)}">${esc(u)}</a></li>`).join('\n')
  : '<li class="leer">Keine verlinkten Quellen im Recherche-Output gefunden.</li>';

const datum = new Date().toLocaleString('de-DE', { dateStyle: 'long', timeStyle: 'short' });

const html = `<!DOCTYPE html>
<html lang="de">
<head>
<meta charset="utf-8">
<title>LinkedIn-Post: ${topic}</title>
<style>
  *, *::before, *::after { box-sizing: border-box; }
  body { margin:0; padding:48px 24px; background:#fafafa; color:#212121;
    font-family: system-ui, -apple-system, "Segoe UI", sans-serif; line-height:1.6;
    -webkit-font-smoothing:antialiased; }
  .sheet { max-width:760px; margin:0 auto; }
  header { background:#212121; color:#fafafa; border-radius:14px 14px 0 0; padding:34px 40px; }
  .eyebrow { text-transform:uppercase; letter-spacing:.14em; font-size:11px; font-weight:600;
    color:#87cdcb; margin:0 0 10px; }
  header h1 { margin:0; font-size:28px; font-weight:600; letter-spacing:-.01em; }
  .badge { display:inline-block; margin-top:18px; padding:6px 14px; border-radius:999px;
    font-size:12px; font-weight:700; letter-spacing:.06em; text-transform:uppercase;
    background:#87cdcb; color:#12302f; }
  .meta { display:flex; flex-wrap:wrap; gap:32px; margin:0; background:#fff;
    border:1px solid #e8e8e8; border-top:none; padding:20px 40px; }
  .meta dt { color:#8a8a8a; font-size:11px; text-transform:uppercase; letter-spacing:.08em;
    margin-bottom:3px; }
  .meta dd { margin:0; font-weight:600; font-size:14px; }
  main { background:#fff; border:1px solid #e8e8e8; border-top:none; border-radius:0 0 14px 14px;
    padding:40px; }
  section + section { margin-top:40px; }
  h2 { font-size:12px; text-transform:uppercase; letter-spacing:.12em; color:#cc8a7a;
    margin:0 0 16px; font-weight:700; }
  .post { border:1px solid #e0e0e0; border-radius:12px; overflow:hidden; }
  .author { display:flex; align-items:center; gap:12px; padding:16px 20px;
    border-bottom:1px solid #f0f0f0; }
  .avatar { width:44px; height:44px; border-radius:50%; background:#212121; color:#87cdcb;
    display:flex; align-items:center; justify-content:center; font-weight:700; font-size:15px; flex:none; }
  .author-name { font-weight:600; font-size:15px; }
  .author-sub { font-size:12px; color:#767676; }
  .post-body { padding:22px 20px; white-space:pre-wrap; font-size:15px; }
  .post-foot { padding:12px 20px; border-top:1px solid #f0f0f0; background:#fbfbfb;
    font-size:12px; color:#767676; display:flex; justify-content:space-between; gap:12px; }
  ul.quellen { list-style:none; margin:0; padding:0; }
  ul.quellen li { padding:10px 0; border-bottom:1px solid #f0f0f0; font-size:14px; word-break:break-all; }
  ul.quellen li:last-child { border-bottom:none; }
  ul.quellen a { color:#212121; text-decoration:none; border-bottom:2px solid #87cdcb; }
  .leer { color:#999; font-style:italic; }
  .brand { background:#f4fbfb; border-left:4px solid #87cdcb; border-radius:0 8px 8px 0;
    padding:18px 22px; white-space:pre-wrap; font-size:14px; }
  footer { text-align:center; color:#a0a0a0; font-size:11px; padding:28px 0 0; }
</style>
</head>
<body>
<div class="sheet">
  <header>
    <p class="eyebrow">Multi-Agent Content-Team</p>
    <h1>LinkedIn-Post</h1>
    <span class="badge">Freigegeben</span>
  </header>
  <dl class="meta">
    <div><dt>Thema</dt><dd>${topic}</dd></div>
    <div><dt>Länge</dt><dd>${zeichen} Zeichen</dd></div>
    <div><dt>Erstellt</dt><dd>${datum}</dd></div>
  </dl>
  <main>
    <section>
      <h2>Post-Vorschau</h2>
      <div class="post">
        <div class="author">
          <div class="avatar">KI</div>
          <div>
            <div class="author-name">KI-Manager Demo</div>
            <div class="author-sub">Automatisiert erstellt vom Content-Team</div>
          </div>
        </div>
        <div class="post-body">${post}</div>
        <div class="post-foot"><span>${zeichen} Zeichen</span><span>Vom Brand-Check freigegeben</span></div>
      </div>
    </section>
    <section>
      <h2>Recherche-Quellen</h2>
      <ul class="quellen">
${quellen}
      </ul>
    </section>
    <section>
      <h2>Brand-Check: Freigabe-Begründung</h2>
      <div class="brand">${brandCheck}</div>
    </section>
  </main>
  <footer>Erzeugt von n8n &middot; Tag 6 Demo: Multi-Agent Content-Team</footer>
</div>
</body>
</html>`;

// Als Base64 -> "Convert to File" (Move Base64 String to File) macht daraus die HTML-Datei
const htmlBase64 = Buffer.from(html, 'utf8').toString('base64');

return [{ json: { ...item, html, htmlBase64, zeichen, quellenAnzahl: urls.length } }];

// Rendert den Eskalations-Report als HTML, wenn der Brand-Check 2x abgelehnt hat.
const item = $input.first().json;

const esc = (s) => String(s ?? '')
